use distributed_inference::loader::KnotWeights;
use distributed_inference::math::mat_vec_q4k_batch;
use std::fs::read;

fn main() -> Result<(), String> {
    let raw = read("/tmp/native-l27-residual.bin").map_err(|e| format!("read: {:?}", e))?;
    let residual: &[f32] =
        unsafe { std::slice::from_raw_parts(raw.as_ptr() as *const f32, raw.len() / 4) };

    let knot = KnotWeights::load("/tmp/qwen-coder-7b.knot").map_err(|e| format!("{:?}", e))?;
    let norm_bytes = knot
        .backend
        .fetch_tensor("output_norm_weight")
        .map_err(|e| format!("{:?}", e))?;
    let norm_w: &[f32] = unsafe {
        std::slice::from_raw_parts(norm_bytes.as_ptr() as *const f32, norm_bytes.len() / 4)
    };

    // Apply RMSNorm to ALL 7 tokens
    let mut post_norm = vec![0f32; 7 * 3584];
    for tok in 0..7 {
        let x = &residual[tok * 3584..(tok + 1) * 3584];
        let sum_sq: f32 = x.iter().map(|v| v * v).sum();
        let inv = 1.0 / (sum_sq / 3584.0 + 1e-6).sqrt();
        for i in 0..3584 {
            post_norm[tok * 3584 + i] = x[i] * inv * norm_w[i];
        }
    }

    let embed_bytes = knot
        .backend
        .fetch_tensor("token_embd_weight")
        .map_err(|e| format!("{:?}", e))?;

    // Batch matmul like lm_head_only
    let xs: Vec<&[f32]> = (0..7)
        .map(|t| &post_norm[t * 3584..(t + 1) * 3584])
        .collect();
    let mut logits_storage: Vec<Vec<f32>> = (0..7).map(|_| vec![0f32; 152064]).collect();
    let mut logits_refs: Vec<&mut [f32]> = logits_storage
        .iter_mut()
        .map(|v| v.as_mut_slice())
        .collect();
    mat_vec_q4k_batch(&mut logits_refs, &xs, &embed_bytes, 152064, 3584);

    println!("== Last token (idx=6) batch result ==");
    println!("logit[576]   = {:.4}", logits_storage[6][576]);
    println!("logit[76291] = {:.4}", logits_storage[6][76291]);
    println!("logit[12095] = {:.4}", logits_storage[6][12095]);
    Ok(())
}
